import React from 'react';
import auth from '../services/auth';

const Topbar = () => {
  const profile = auth.getProfile();
  return (
    <div className="topbar">
      <div>
        <h2 className="page-title">Admin Panel</h2>
        <div style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>Welcome back, {profile?.email || 'Administrator'}</div>
      </div>
      <div style={{ display: 'flex', gap: 12, alignItems: 'center' }}>
        <div className="status-badge status-active">Authorized</div>
        <button className="btn btn-secondary" onClick={() => { auth.logout(); window.location.href = '/login'; }}>Logout</button>
      </div>
    </div>
  );
}

export default Topbar;
